using Microsoft.AspNetCore.Mvc; using VoiceAgent.Application.Interfaces; using VoiceAgent.Common.Responses;
namespace VoiceAgent.Api.Controllers; [ApiController][Route("api/[controller]")] public class KnowledgeBaseController(IKnowledgeBaseService service):ControllerBase{ [HttpPost("/api/knowledge-bases")] public async Task<ActionResult<ApiResponse<Guid>>> CreateBase([FromBody] object request,CancellationToken ct)=>Ok(new ApiResponse<Guid>{Success=true,Data=await service.CreateBaseAsync(request,ct)}); [HttpPost("/api/knowledge-documents")] public ActionResult<ApiResponse<object>> CreateDocument([FromBody] object request)=>Ok(new ApiResponse<object>{Success=true,Data=request}); [HttpPost("/api/knowledge/search")] public ActionResult<ApiResponse<object>> Search([FromBody] object request)=>Ok(new ApiResponse<object>{Success=true,Data=Array.Empty<object>()}); [HttpPost("/api/knowledge/reindex")] public ActionResult<ApiResponse<object>> Reindex([FromBody] object request)=>Ok(new ApiResponse<object>{Success=true,Data=new{accepted=true}}); }
